import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useFormValidation, ValidatedInput, commonValidations } from './FormValidation';
import { useNotifications, useErrorHandler } from './NotificationSystem';

const Login: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const { showSuccess } = useNotifications();
  const { handleError } = useErrorHandler();

  const {
    values,
    errors,
    touched,
    handleChange,
    handleBlur,
    validateForm,
  } = useFormValidation(
    {
      email: process.env.NODE_ENV === 'development' ? 'admin@granja.com' : '',
      password: process.env.NODE_ENV === 'development' ? 'admin123' : '',
    },
    {
      email: commonValidations.email,
      password: commonValidations.password,
    }
  );

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setLoading(true);

    try {
      await login(values.email, values.password);
      showSuccess('Bienvenido', 'Inicio de sesión exitoso');
    } catch (err: any) {
      handleError(err, 'Error de autenticación');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '20px'
    }}>
      <div style={{
        background: 'rgba(255, 255, 255, 0.95)',
        backdropFilter: 'blur(10px)',
        borderRadius: '20px',
        padding: '40px',
        width: '100%',
        maxWidth: '450px',
        boxShadow: '0 20px 40px rgba(0,0,0,0.1)',
        border: '1px solid rgba(255,255,255,0.2)'
      }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '40px' }}>
          <div style={{ 
            fontSize: '80px', 
            marginBottom: '20px',
            background: 'linear-gradient(135deg, #667eea, #764ba2)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            backgroundClip: 'text'
          }}>
            🐷
          </div>
          <h1 style={{ 
            color: '#2c3e50', 
            marginBottom: '10px',
            fontSize: '28px',
            fontWeight: '700'
          }}>
            Sistema de Gestión Porcina
          </h1>
          <p style={{ 
            color: '#7f8c8d',
            fontSize: '16px',
            margin: 0
          }}>
            Tecnología avanzada para tu granja
          </p>
        </div>



        <form onSubmit={handleSubmit}>
          <ValidatedInput
            name="email"
            label="📧 Correo Electrónico"
            type="email"
            value={values.email}
            error={errors.email}
            touched={touched.email}
            onChange={handleChange}
            onBlur={handleBlur}
            placeholder="Ingresa tu email"
            disabled={loading}
          />

          <ValidatedInput
            name="password"
            label="🔒 Contraseña"
            type="password"
            value={values.password}
            error={errors.password}
            touched={touched.password}
            onChange={handleChange}
            onBlur={handleBlur}
            placeholder="Ingresa tu contraseña"
            disabled={loading}
          />

          <button
            type="submit"
            className="btn btn-primary"
            style={{ 
              width: '100%',
              padding: '15px',
              fontSize: '16px',
              fontWeight: '600',
              borderRadius: '12px',
              background: 'linear-gradient(135deg, #667eea, #764ba2)',
              border: 'none',
              marginTop: '10px',
              minHeight: '54px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '10px'
            }}
            disabled={loading}
          >
            {loading ? (
              <>
                <div className="loading-spinner" style={{ 
                  width: '20px', 
                  height: '20px',
                  borderWidth: '2px'
                }}></div>
                Ingresando...
              </>
            ) : (
              <>
                🚀 Ingresar al Sistema
              </>
            )}
          </button>
        </form>

        {/* Credenciales por defecto */}
        <div style={{ 
          marginTop: '30px', 
          padding: '20px', 
          background: 'linear-gradient(135deg, #f8f9fa, #e9ecef)', 
          borderRadius: '12px',
          border: '1px solid #dee2e6'
        }}>
          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            marginBottom: '12px',
            color: '#495057'
          }}>
            <span style={{ fontSize: '20px', marginRight: '8px' }}>💡</span>
            <strong>Credenciales de Demostración</strong>
          </div>
          <div style={{ fontSize: '14px', color: '#6c757d', lineHeight: '1.6' }}>
            <div style={{ marginBottom: '5px' }}>
              <strong>Email:</strong> admin@granja.com
            </div>
            <div>
              <strong>Contraseña:</strong> admin123
            </div>
          </div>
        </div>

        {/* Footer */}
        <div style={{ 
          textAlign: 'center', 
          marginTop: '30px',
          paddingTop: '20px',
          borderTop: '1px solid #e9ecef'
        }}>
          <p style={{ 
            color: '#7f8c8d', 
            fontSize: '12px',
            margin: 0
          }}>
            © 2025 Sistema de Gestión Porcina v1.0
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
